## Common patterns

### Document operations

Common pattern for document save operations with multiple options:

```jsx-live-dev
const App = () => {
  const [status, setStatus] = useState<string>('No action taken');
  const [isSaving, setIsSaving] = useState(false);

  const handleAction = async (id: string) => {
    setIsSaving(true);
    setStatus(`Executing: ${id}...`);

    // Simulate async operation
    await new Promise(resolve => setTimeout(resolve, 1000));

    setIsSaving(false);
    setStatus(`Completed: ${id}`);
  };

  return (
    <Stack direction="column" gap="400">
      <SplitButton
        onAction={handleAction}
        aria-label="Save options"
        icon={<Icons.Save />}
        isDisabled={isSaving}
      >
        <Menu.Item id="save">Save Draft</Menu.Item>
        <Menu.Item id="save-publish">Save and Publish</Menu.Item>
        <Menu.Item id="save-schedule">Save and Schedule</Menu.Item>
        <Menu.Item id="save-template">Save as Template</Menu.Item>
      </SplitButton>
      <Text fontSize="sm" color="neutral.11">
        {status}
      </Text>
    </Stack>
  );
}
```

### Conditional actions based on state

Show different actions based on application state:

```jsx-live-dev
const App = () => {
  const [isPublished, setIsPublished] = useState(false);
  const [lastAction, setLastAction] = useState<string>('');

  const handleAction = (id: string) => {
    if (id === 'publish') {
      setIsPublished(true);
      setLastAction('Document published');
    } else if (id === 'unpublish') {
      setIsPublished(false);
      setLastAction('Document unpublished');
    } else {
      setLastAction(`Action: ${id}`);
    }
  };

  return (
    <Stack direction="column" gap="400">
      <Text fontSize="sm" fontWeight="semibold">
        Status: {isPublished ? 'Published' : 'Draft'}
      </Text>

      {isPublished ? (
        <SplitButton
          onAction={handleAction}
          aria-label="Published document actions"
          icon={<Icons.Visibility />}
          colorPalette="primary"
        >
          <Menu.Item id="unpublish">Unpublish</Menu.Item>
          <Menu.Item id="update">Update Published Version</Menu.Item>
          <Menu.Item id="analytics">View Analytics</Menu.Item>
          <Menu.Item id="share">Share Link</Menu.Item>
        </SplitButton>
      ) : (
        <SplitButton
          onAction={handleAction}
          aria-label="Draft document actions"
          icon={<Icons.Save />}
        >
          <Menu.Item id="publish">Publish Document</Menu.Item>
          <Menu.Item id="save-draft">Save Draft</Menu.Item>
          <Menu.Item id="preview">Preview</Menu.Item>
          <Menu.Item id="discard">Discard Changes</Menu.Item>
        </SplitButton>
      )}

      {lastAction && (
        <Text fontSize="sm" color="neutral.11">
          {lastAction}
        </Text>
      )}
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using SplitButton within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the SplitButton renders with expected structure and elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { SplitButton, Menu, NimbusProvider } from "@commercetools/nimbus";

describe("SplitButton - Basic rendering", () => {
  it("renders primary button and dropdown trigger", () => {
    render(
      <NimbusProvider>
        <SplitButton onAction={vi.fn()} aria-label="More actions">
          <Menu.Item id="save">Save</Menu.Item>
          <Menu.Item id="export">Export</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    // Primary button should show first action
    const buttons = screen.getAllByRole("button");
    expect(buttons.length).toBeGreaterThanOrEqual(2);

    // Dropdown trigger should have aria-label
    const dropdownTrigger = screen.getByRole("button", {
      name: /More actions/i,
    });
    expect(dropdownTrigger).toBeInTheDocument();
  });

  it("displays first enabled menu item as primary action", () => {
    render(
      <NimbusProvider>
        <SplitButton onAction={vi.fn()} aria-label="Actions">
          <Menu.Item id="save">Save Document</Menu.Item>
          <Menu.Item id="export">Export</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    // Primary button should show "Save Document"
    expect(screen.getByText("Save Document")).toBeInTheDocument();
  });

  it("renders with icon in primary button", () => {
    const TestIcon = () => <svg data-testid="test-icon" />;

    render(
      <NimbusProvider>
        <SplitButton
          onAction={vi.fn()}
          aria-label="Actions"
          icon={<TestIcon />}
        >
          <Menu.Item id="save">Save</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    expect(screen.getByTestId("test-icon")).toBeInTheDocument();
  });

  it("renders with different sizes", () => {
    const { rerender } = render(
      <NimbusProvider>
        <SplitButton size="2xs" onAction={vi.fn()} aria-label="Actions">
          <Menu.Item id="save">Save</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    expect(
      screen.getByRole("button", { name: /Actions/i })
    ).toBeInTheDocument();

    rerender(
      <NimbusProvider>
        <SplitButton size="md" onAction={vi.fn()} aria-label="Actions">
          <Menu.Item id="save">Save</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    expect(
      screen.getByRole("button", { name: /Actions/i })
    ).toBeInTheDocument();
  });
});
```

### Interaction Tests

Test user interactions with primary button and dropdown menu

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { SplitButton, Menu, NimbusProvider } from "@commercetools/nimbus";

describe("SplitButton - Interactions", () => {
  it("executes primary action when primary button is clicked", async () => {
    const user = userEvent.setup();
    const handleAction = vi.fn();

    render(
      <NimbusProvider>
        <SplitButton onAction={handleAction} aria-label="Actions">
          <Menu.Item id="save">Save</Menu.Item>
          <Menu.Item id="export">Export</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    const primaryButton = screen.getByText("Save");
    await user.click(primaryButton);

    expect(handleAction).toHaveBeenCalledWith("save");
  });

  it("opens dropdown menu when trigger is clicked", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <SplitButton onAction={vi.fn()} aria-label="More actions">
          <Menu.Item id="save">Save</Menu.Item>
          <Menu.Item id="export">Export</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    const dropdownTrigger = screen.getByRole("button", {
      name: /More actions/i,
    });
    await user.click(dropdownTrigger);

    await waitFor(() => {
      expect(screen.getByRole("menu")).toBeInTheDocument();
    });
  });

  it("executes selected menu item action", async () => {
    const user = userEvent.setup();
    const handleAction = vi.fn();

    render(
      <NimbusProvider>
        <SplitButton onAction={handleAction} aria-label="Actions">
          <Menu.Item id="save">Save</Menu.Item>
          <Menu.Item id="export">Export</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    // Open menu
    const dropdownTrigger = screen.getByRole("button", { name: /Actions/i });
    await user.click(dropdownTrigger);

    // Click menu item
    await waitFor(() => {
      expect(screen.getByRole("menu")).toBeInTheDocument();
    });

    const exportItem = screen.getByRole("menuitem", { name: /Export/i });
    await user.click(exportItem);

    expect(handleAction).toHaveBeenCalledWith("export");
  });

  it("closes menu after selecting an item", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <SplitButton onAction={vi.fn()} aria-label="Actions">
          <Menu.Item id="save">Save</Menu.Item>
          <Menu.Item id="export">Export</Menu.Item>
        </SplitButton>
      </NimbusProvider>
    );

    // Open menu
    const dropdownTrigger = screen.getByRole("button", { name: /Actions/i });
    await user.click(dropdownTrigger);

    await waitFor(() => {
      expect(screen.getByRole("menu")).toBeInTheDocument();
    });

    // Select item
    const saveItem = screen.getByRole("menuitem", { name: /Save/i });
    await user.click(saveItem);

    // Menu should close
    await waitFor(() => {
      expect(screen.queryByRole("menu")).not.toBeInTheDocument();
    });
  });
});
```

